import { prisma } from "@/lib/prisma";
import { Package, ArrowLeft, Save, Image as ImageIcon } from "lucide-react";
import Link from "next/link";
import { redirect } from "next/navigation";
import { revalidatePath } from "next/cache";
import { uploadImage } from "@/lib/r2";

async function saveProduct(formData: FormData) {
  "use server";
  
  const id = formData.get("id") as string | null;
  const name = formData.get("name") as string;
  const description = formData.get("description") as string;
  const category = formData.get("category") as string;
  const price = parseFloat(formData.get("price") as string);
  const stock = parseInt(formData.get("stock") as string);
  const imageFile = formData.get("image") as File;

  let imageUrl = formData.get("currentImageUrl") as string | null;

  // Se um novo arquivo foi enviado, faz o upload
  if (imageFile && imageFile.size > 0) {
    const uploadedUrl = await uploadImage(imageFile);
    if (uploadedUrl) {
      imageUrl = uploadedUrl;
    }
  }

  const data = { 
    name, 
    description, 
    category, 
    price, 
    stock,
    image: imageUrl
  };

  if (id) {
    await prisma.product.update({
      where: { id },
      data,
    });
  } else {
    await prisma.product.create({
      data,
    });
  }

  revalidatePath("/estoque");
  revalidatePath("/");
  redirect("/estoque");
}

export default async function ProductFormPage({
  params,
}: {
  params: Promise<{ id?: string }>;
}) {
  const id = (await params).id;
  const product = id ? await prisma.product.findUnique({ where: { id } }) : null;

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <Link href="/estoque" className="flex items-center gap-2 text-scout-blue hover:text-scout-green font-bold uppercase text-[10px] tracking-widest transition-colors">
        <ArrowLeft className="w-4 h-4" />
        Voltar para o estoque
      </Link>

      <div className="flex items-center gap-4">
        <div className="bg-scout-green p-3 rounded-2xl text-white shadow-lg shadow-scout-green/20">
          <Package className="w-8 h-8" />
        </div>
        <div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">
            {product ? "Ajustar Item" : "Novo Cadastro"}
          </h1>
          <p className="text-scout-green font-bold uppercase text-[10px] tracking-[0.3em]">
            {product ? product.name : "Entrada de Patrimônio"}
          </p>
        </div>
      </div>

      <form action={saveProduct} className="bg-white rounded-[2rem] border border-gray-100 shadow-sm p-10 space-y-8">
        <input type="hidden" name="id" value={product?.id || ""} />
        <input type="hidden" name="currentImageUrl" value={product?.image || ""} />
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Campo de Imagem */}
          <div className="md:col-span-2 space-y-4">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
              Foto do Produto
            </label>
            <div className="flex flex-col md:flex-row items-center gap-6">
              <div className="w-32 h-32 bg-gray-50 border-2 border-dashed border-gray-200 rounded-3xl flex items-center justify-center overflow-hidden shrink-0">
                {product?.image ? (
                  <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                ) : (
                  <ImageIcon className="w-8 h-8 text-gray-300" />
                )}
              </div>
              <div className="flex-grow w-full">
                <input
                  type="file"
                  name="image"
                  accept="image/*"
                  className="w-full text-xs text-gray-500 file:mr-4 file:py-2.5 file:px-6 file:rounded-full file:border-0 file:text-[10px] file:font-black file:uppercase file:tracking-widest file:bg-scout-blue/10 file:text-scout-blue hover:file:bg-scout-blue/20 transition-all cursor-pointer"
                />
                <p className="text-[10px] text-gray-400 mt-2">Recomendado: Quadrado (1:1), JPG ou PNG.</p>
              </div>
            </div>
          </div>

          <div className="space-y-2 md:col-span-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
              Nome do Item
            </label>
            <input
              type="text"
              name="name"
              defaultValue={product?.name || ""}
              required
              className="w-full input-scout"
              placeholder="Ex: Camiseta do Grupo, Lenço, etc."
            />
          </div>

          <div className="space-y-2 md:col-span-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
              Descrição Técnica
            </label>
            <textarea
              name="description"
              defaultValue={product?.description || ""}
              className="w-full input-scout min-h-[120px] resize-none"
              placeholder="Detalhes sobre o tamanho, cor, material..."
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
              Categoria
            </label>
            <input
              type="text"
              name="category"
              defaultValue={product?.category || ""}
              className="w-full input-scout"
              placeholder="Ex: Uniforme, Acessório"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
              Preço Institucional (R$)
            </label>
            <input
              type="number"
              step="0.01"
              name="price"
              defaultValue={product?.price || ""}
              required
              className="w-full input-scout"
              placeholder="0,00"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">
              Quantidade em Estoque
            </label>
            <input
              type="number"
              name="stock"
              defaultValue={product?.stock || 0}
              required
              className="w-full input-scout"
              placeholder="0"
            />
          </div>
        </div>

        <div className="pt-6 flex flex-col sm:flex-row gap-4">
          <button type="submit" className="flex-grow btn-scout-primary h-14 justify-center text-base">
            <Save className="w-5 h-5" />
            {product ? "Salvar Alterações" : "Efetivar Cadastro"}
          </button>
          <Link href="/estoque" className="px-10 h-14 flex items-center justify-center bg-gray-50 text-gray-400 rounded-full font-black uppercase tracking-widest text-[10px] hover:bg-gray-100 transition-all border border-gray-100">
            Descartar
          </Link>
        </div>
      </form>
    </div>
  );
}
